import torch
import pickle


def resume_training_from_checkpoint(checkpoint_path: str) -> dict:
    """
    Load a training checkpoint from the specified path and return its contents.

    Args:
        checkpoint_path: Path to the checkpoint file (.ckpt or .pth)

    Returns:
        Dictionary containing model state, optimizer state, and training metadata
    """
    try:
        checkpoint_data = torch.load(checkpoint_path)
    except FileNotFoundError as e:
        raise FileNotFoundError(
            f"Checkpoint file not found at path: {checkpoint_path}. Please verify the path is correct."
        ) from e
    except PermissionError as e:
        raise PermissionError(
            f"Permission denied when reading checkpoint file at {checkpoint_path}. Ensure you have read access to the file."
        ) from e
    except IsADirectoryError as e:
        raise IsADirectoryError(
            f"Provided checkpoint path {checkpoint_path} is a directory, not a file."
        ) from e
    except (pickle.UnpicklingError, EOFError, RuntimeError) as e:
        raise RuntimeError(
            f"Failed to load checkpoint from {checkpoint_path}: The file may be corrupted, not a valid PyTorch checkpoint, or incompatible with your current PyTorch version. Original error: {str(e)}"
        ) from e

    if not isinstance(checkpoint_data, dict):
        raise TypeError(
            f"Loaded checkpoint from {checkpoint_path} is of type {type(checkpoint_data).__name__}, expected a dictionary."
        )

    return checkpoint_data
